1	import React, { useState, useRef, useEffect } from 'react';
2	import ReactDOM from 'react-dom';
3	import { useTranslation } from 'react-i18next';
4	import './AIChat.css';
5	import ChatMessage from '../components/ChatMessage';
6	import { ai, profile as profileApi } from '../api/api';
7	import type { AiPreferences } from '../api/api';
8	
9	interface Message {
10	  id: string;
11	  role: 'user' | 'ai' | 'system';
12	  content: string;
13	  timestamp: Date;
14	}
15	
16	interface AIChatProps {
17	  onWorkoutClick?: (id: string) => void;
18	  isActive?: boolean;
19	}
20	
21	const AIChat: React.FC<AIChatProps> = ({ onWorkoutClick, isActive }) => {
22	  const { t } = useTranslation();
23	
24	  const QUICK_QUESTIONS = [
25	    t('chat.q1'),
26	    t('chat.q2'),
27	    t('chat.q3'),
28	    t('chat.q4'),
29	    t('chat.q5'),
30	    t('chat.q6'),
31	  ];
32	
33	  const WELCOME_MESSAGE: Message = {
34	    id: '1',
35	    role: 'ai',
36	    content: t('chat.welcome'),
37	    timestamp: new Date()
38	  };
39	
40	  const AI_DEFAULTS: AiPreferences = {
41	    coach_gender: 'male',
42	    response_length: 'medium',
43	    personality: 'bro',
44	    humor: true,
45	    emoji_level: 'few'
46	  };
47	
48	  const [messages, setMessages] = useState<Message[]>([WELCOME_MESSAGE]);
49	  const [inputValue, setInputValue] = useState('');
50	  const [loading, setLoading] = useState(false);
51	  const [historyLoaded, setHistoryLoaded] = useState(false);
52	  const [updatingPlan, setUpdatingPlan] = useState(false);
53	  const [thinking, setThinking] = useState(false);
54	  const [showAiSettings, setShowAiSettings] = useState(false);
55	  const [aiSettingsClosing, setAiSettingsClosing] = useState(false);
56	  const [aiPrefs, setAiPrefs] = useState<AiPreferences>(AI_DEFAULTS);
57	  const [savingPrefs, setSavingPrefs] = useState(false);
58	  const [messageLimit, setMessageLimit] = useState<{ limit: number; used: number; remaining: number } | null>(null);
59	  const messagesEndRef = useRef<HTMLDivElement>(null);
60	  const messagesContainerRef = useRef<HTMLDivElement>(null);
61	  const userScrolledUp = useRef(false);
62	
63	  const scrollRestoredRef = useRef(false);
64	
65	  const scrollToBottom = () => {
66	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
67	  };
68	
69	  // Only auto-scroll if user hasn't scrolled up
70	  useEffect(() => {
71	    if (!userScrolledUp.current && scrollRestoredRef.current) {
72	      scrollToBottom();
73	    }
74	  }, [messages]);
75	
76	  // Detect if user scrolled up
77	  const handleScroll = () => {
78	    const container = messagesContainerRef.current;
79	    if (!container) return;
80	    const threshold = 100;
