/* ============ AI CHAT SCREEN ============ */
.ai-chat-screen {
  display: flex;
  flex-direction: column;
  height: calc(100vh - 68px);
  overflow: hidden;
  padding: var(--spacing-sm) var(--spacing-lg) 0;
  width: 100%;
  max-width: 420px;
  align-self: center;
}

.chat-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 0;
  margin-bottom: 2px;
  flex-shrink: 0;
}

.chat-header .screen-title {
  margin: 0;
  font-size: 18px;
}

.chat-limit-banner {
  text-align: center;
  font-size: 13px;
  color: #f59e0b;
  padding: 6px 12px;
  background: rgba(245, 158, 11, 0.1);
  border-radius: 8px;
  margin-bottom: 8px;
}


.chat-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  gap: var(--spacing-sm);
}

.messages {
  flex: 1;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}

.messages::-webkit-scrollbar {
  display: none;
}

.message {
  display: flex;
  animation: slideIn 0.3s ease-out;
}

.message.user-message {
  justify-content: flex-end;
}

.message.ai-message {
  justify-content: flex-start;
}

.message-content {
  max-width: 80%;
  padding: var(--spacing-md);
  border-radius: var(--radius-lg);
  word-wrap: break-word;
  line-height: 1.4;
}

.user-message .message-content {
  background-color: var(--color-accent);
  color: white;
}

.ai-message .message-content {
  background-color: var(--color-bg-secondary);
  color: var(--color-text);
  border: 1px solid var(--color-border);
}

.message.system-message {
  justify-content: center;
}

.system-message .message-content {
  background-color: rgba(34, 197, 94, 0.15);
  color: #22c55e;
  border: 1px solid rgba(34, 197, 94, 0.3);
  text-align: center;
  font-size: 13px;
  font-weight: 500;
}

.plan-updating {
  background-color: rgba(234, 179, 8, 0.15) !important;
  color: #eab308 !important;
  border: 1px solid rgba(234, 179, 8, 0.3) !important;
  display: flex;
  align-items: center;
  gap: 8px;
}

.plan-updating-spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(234, 179, 8, 0.3);
  border-top-color: #eab308;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

.thinking-indicator {
  display: flex;
  align-items: center;
  gap: 8px;
  color: #60a5fa;
  font-size: 0.9em;
}

.thinking-spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(96, 165, 250, 0.3);
  border-top-color: #60a5fa;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

/* Workout link chips inside AI messages */
.workout-link {
  background: none;
  border: none;
  padding: 0;
  margin: 0;
  font: inherit;
  font-size: inherit;
  color: #60a5fa;
  text-decoration: underline;
  text-decoration-style: solid;
  text-underline-offset: 3px;
  cursor: pointer;
}

.quick-questions {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex-shrink: 0;
}

.quick-questions-label {
  font-size: 11px;
  color: var(--color-text-secondary);
  font-weight: 500;
}

.quick-questions-grid {
  display: flex;
  gap: var(--spacing-sm);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
  padding-bottom: 2px;
}

.quick-questions-grid::-webkit-scrollbar {
  display: none;
}

.quick-btn {
  font-size: 12px;
  padding: 6px 12px;
  background-color: var(--color-bg-secondary);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text);
  cursor: pointer;
  transition: var(--transition);
  text-align: left;
  white-space: nowrap;
  flex-shrink: 0;
}

.quick-btn:active:not(:disabled) {
  border-color: var(--color-accent);
  background-color: var(--color-border);
}

.quick-btn:disabled {
  opacity: 0.5;
}

.chat-input-area {
  position: fixed;
  bottom: 68px;
  left: 50%;
  transform: translateX(-50%);
  width: 100%;
  max-width: 420px;
  padding: 0 var(--spacing-lg) 6px;
  display: flex;
  gap: var(--spacing-sm);
  flex-direction: column;
  background-color: var(--color-bg);
  z-index: 50;
}

.chat-input-wrapper {
  display: flex;
  gap: var(--spacing-sm);
  align-items: center;
  background-color: var(--color-bg-secondary);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--spacing-sm);
  flex: 1;
}

.chat-input {
  flex: 1;
  background: none;
  border: none;
  color: var(--color-text);
  font-size: 14px;
  outline: none;
  box-shadow: none;
  -webkit-appearance: none;
  font-family: inherit;
}

.chat-input:focus {
  outline: none;
  box-shadow: none;
}

.chat-input::placeholder {
  color: var(--color-text-secondary);
}

.chat-send-btn {
  background: none;
  border: none;
  color: var(--color-accent);
  font-size: 18px;
  cursor: pointer;
  padding: var(--spacing-sm);
}

.chat-settings-btn {
  background: none;
  border: none;
  color: var(--color-text-secondary);
  padding: 4px;
  cursor: pointer;
  border-radius: var(--radius-sm);
  transition: color 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.chat-settings-btn:hover {
  color: var(--color-text);
}

.chat-settings-btn:active {
  color: var(--color-accent);
}

/* ============ AI SETTINGS MODAL ============ */
.ai-settings-section {
  margin-bottom: var(--spacing-md);
}

.ai-settings-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.ai-option-group {
  display: flex;
  gap: 6px;
}

.ai-option-group-3 {
  display: flex;
  gap: 6px;
}

.ai-option-group-3 .ai-option-btn {
  flex: 1;
}

.ai-option-btn {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  background: transparent;
  color: var(--color-text-secondary);
  font-size: 13px;
  cursor: pointer;
  transition: all 0.2s ease;
  text-align: center;
  white-space: nowrap;
}

.ai-option-btn:hover {
  border-color: var(--color-accent);
  color: var(--color-text);
}

.ai-option-btn.active {
  border-color: var(--color-accent);
  background: rgba(59, 130, 246, 0.15);
  color: var(--color-text);
}

/* ============ AI LIMIT IN SETTINGS ============ */

.ai-limit-section {
  border-top: 1px solid var(--color-border);
  padding-top: 14px;
  margin-top: 6px;
}

.ai-limit-bar-wrapper {
  display: flex;
  align-items: center;
  gap: 10px;
}

.ai-limit-bar {
  flex: 1;
  height: 6px;
  background: var(--color-border);
  border-radius: 3px;
  overflow: hidden;
}

.ai-limit-bar-fill {
  height: 100%;
  background: var(--color-accent);
  border-radius: 3px;
  transition: width 0.3s ease;
}

.ai-limit-bar-fill.low {
  background: #f59e0b;
}

.ai-limit-text {
  font-size: 12px;
  color: var(--color-text-secondary);
  white-space: nowrap;
}

.ai-limit-text.low {
  color: #f59e0b;
}

.personality-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}

.btn-danger-outline {
  background: transparent;
  border: 1px solid var(--color-danger);
  color: var(--color-danger);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
}

.btn-danger-outline:active {
  background: rgba(239, 68, 68, 0.15);
}

import React, { useState, useRef, useEffect } from 'react';
import ReactDOM from 'react-dom';
import { useTranslation } from 'react-i18next';
import './AIChat.css';
import ChatMessage from '../components/ChatMessage';
import { ai, profile as profileApi } from '../api/api';
import type { AiPreferences } from '../api/api';

interface Message {
  id: string;
  role: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
}

interface AIChatProps {
  onWorkoutClick?: (id: string) => void;
  isActive?: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ onWorkoutClick, isActive }) => {
  const { t } = useTranslation();

  const QUICK_QUESTIONS = [
    t('chat.q1'),
    t('chat.q2'),
    t('chat.q3'),
    t('chat.q4'),
    t('chat.q5'),
    t('chat.q6'),
  ];

  const WELCOME_MESSAGE: Message = {
    id: '1',
    role: 'ai',
    content: t('chat.welcome'),
    timestamp: new Date()
  };

  const AI_DEFAULTS: AiPreferences = {
    coach_gender: 'male',
    response_length: 'medium',
    personality: 'bro',
    humor: true,
    emoji_level: 'few'
  };

  const [messages, setMessages] = useState<Message[]>([WELCOME_MESSAGE]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(false);
  const [historyLoaded, setHistoryLoaded] = useState(false);
  const [updatingPlan, setUpdatingPlan] = useState(false);
  const [thinking, setThinking] = useState(false);
  const [showAiSettings, setShowAiSettings] = useState(false);
  const [aiSettingsClosing, setAiSettingsClosing] = useState(false);
  const [aiPrefs, setAiPrefs] = useState<AiPreferences>(AI_DEFAULTS);
  const [savingPrefs, setSavingPrefs] = useState(false);
  const [messageLimit, setMessageLimit] = useState<{ limit: number; used: number; remaining: number } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messagesContainerRef = useRef<HTMLDivElement>(null);
  const userScrolledUp = useRef(false);

  const scrollRestoredRef = useRef(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Only auto-scroll if user hasn't scrolled up
  useEffect(() => {
    if (!userScrolledUp.current && scrollRestoredRef.current) {
      scrollToBottom();
    }
  }, [messages]);

  // Detect if user scrolled up
  const handleScroll = () => {
    const container = messagesContainerRef.current;
    if (!container) return;
    const threshold = 100;
    const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
    userScrolledUp.current = distanceFromBottom > threshold;
  };

  // Always scroll to bottom after history loads
  useEffect(() => {
    if (historyLoaded && messagesContainerRef.current) {
      requestAnimationFrame(() => {
        messagesEndRef.current?.scrollIntoView();
        scrollRestoredRef.current = true;
      });
    }
  }, [historyLoaded]);

  // Scroll to bottom when tab becomes active (container was hidden, scrollIntoView didn't work)
  useEffect(() => {
    if (isActive && historyLoaded) {
      requestAnimationFrame(() => {
        messagesEndRef.current?.scrollIntoView();
      });
    }
  }, [isActive]);

  // Load chat history and AI prefs on mount
  useEffect(() => {
    const loadHistory = async () => {
      try {
        const history = await ai.chatHistory();
        if (history && history.length > 0) {
          const loaded: Message[] = [WELCOME_MESSAGE, ...history.map((m: any) => ({
            id: m.id,
            role: m.role as 'user' | 'ai',
            content: m.content,
            timestamp: new Date(m.created_at)
          }))];
          setMessages(loaded);
        }
      } catch (err) {
        console.error('Failed to load chat history:', err);
      } finally {
        setHistoryLoaded(true);
      }
    };
    loadHistory();

    // Load message limit
    ai.chatLimit().then((data: any) => {
      if (data) setMessageLimit(data);
    }).catch(() => {});

    // Load AI preferences
    const cached = localStorage.getItem('runwise_ai_prefs');
    if (cached) {
      try { setAiPrefs({ ...AI_DEFAULTS, ...JSON.parse(cached) }); } catch {}
    }
    profileApi.get().then((data: any) => {
      if (data?.ai_preferences) {
        const prefs = { ...AI_DEFAULTS, ...data.ai_preferences };
        setAiPrefs(prefs);
        localStorage.setItem('runwise_ai_prefs', JSON.stringify(prefs));
      }
    }).catch(() => {});
  }, []);

  const handleClearHistory = async () => {
    if (!window.confirm(t('chat.clearConfirm'))) return;
    try {
      await ai.clearChatHistory();
      setMessages([WELCOME_MESSAGE]);
    } catch (err) {
      console.error('Failed to clear history:', err);
    }
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;
    if (messageLimit && messageLimit.remaining <= 0) return;

    // Add user message
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setLoading(true);
    userScrolledUp.current = false;

    const aiMessageId = (Date.now() + 1).toString();
    let firstChunk = true;
    let fullContent = '';

    // Strip ===PLAN_UPDATE===...===END_PLAN_UPDATE=== and ===MACRO_PLAN_UPDATE===...===END_MACRO_PLAN_UPDATE=== blocks from displayed text
    const stripPlanBlock = (text: string) => {
      let result = text;
      // Strip weekly plan block
      const planStart = result.indexOf('===PLAN_UPDATE===');
      if (planStart !== -1) {
        const planEnd = result.indexOf('===END_PLAN_UPDATE===');
        if (planEnd !== -1) {
          result = result.substring(0, planStart) + result.substring(planEnd + '===END_PLAN_UPDATE==='.length);
        } else {
          result = result.substring(0, planStart);
        }
      }
      // Strip macro plan block
      const macroStart = result.indexOf('===MACRO_PLAN_UPDATE===');
      if (macroStart !== -1) {
        const macroEnd = result.indexOf('===END_MACRO_PLAN_UPDATE===');
        if (macroEnd !== -1) {
          result = result.substring(0, macroStart) + result.substring(macroEnd + '===END_MACRO_PLAN_UPDATE==='.length);
        } else {
          result = result.substring(0, macroStart);
        }
      }
      return result.trim();
    };

    try {
      // Add empty AI message that will be filled progressively
      const aiMessage: Message = {
        id: aiMessageId,
        role: 'ai',
        content: '',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMessage]);

      await ai.chatStream(
        text,
        (chunk: string) => {
          if (firstChunk) {
            firstChunk = false;
            setLoading(false);
            setThinking(false);
          }
          fullContent += chunk;
          const displayContent = stripPlanBlock(fullContent);
          // Show "updating plan" indicator when plan block starts streaming
          if (fullContent.includes('===PLAN_UPDATE===') || fullContent.includes('===MACRO_PLAN_UPDATE===')) {
            setUpdatingPlan(true);
          }
          setMessages(prev =>
            prev.map(m =>
              m.id === aiMessageId ? { ...m, content: displayContent } : m
            )
          );
        },
        (meta: { planUpdated: boolean; macroPlanUpdated?: boolean; macroPlanAction?: string }) => {
          setUpdatingPlan(false);
          setThinking(false);
          // Final cleanup: strip plan block from displayed message
          const cleanContent = stripPlanBlock(fullContent);
          setMessages(prev =>
            prev.map(m =>
              m.id === aiMessageId ? { ...m, content: cleanContent } : m
            )
          );
          if (meta.planUpdated) {
            // Clear cached plan so Plan screen fetches fresh data
            try { localStorage.removeItem('rw_plan_cache'); } catch {}
            const systemMsg: Message = {
              id: (Date.now() + 2).toString(),
              role: 'system',
              content: t('chat.planUpdated'),
              timestamp: new Date()
            };
            setMessages(prev => [...prev, systemMsg]);
          }
          if (meta.macroPlanUpdated) {
            // Clear cached macro plan so Plan screen fetches fresh data
            try { localStorage.removeItem('rw_macro_plan_cache'); } catch {}
            const macroMsg: Message = {
              id: (Date.now() + 3).toString(),
              role: 'system',
              content: meta.macroPlanAction === 'created'
                ? t('chat.macroPlanCreated')
                : meta.macroPlanAction === 'deleted'
                  ? t('chat.macroPlanDeleted')
                  : t('chat.macroPlanUpdated'),
              timestamp: new Date()
            };
            setMessages(prev => [...prev, macroMsg]);
          }
        },
        () => {
          setThinking(true);
        }
      );
      // Update limit after successful send
      ai.chatLimit().then((data: any) => {
        if (data) setMessageLimit(data);
      }).catch(() => {});
    } catch (err: any) {
      console.error('Chat error:', err);
      const isLimitError = err?.message?.includes('limit') || err?.message?.includes('429');
      setMessages(prev =>
        prev.map(m =>
          m.id === aiMessageId
            ? { ...m, content: isLimitError ? t('chat.limitReached') : t('chat.error') }
            : m
        )
      );
      if (isLimitError) {
        setMessageLimit(prev => prev ? { ...prev, remaining: 0 } : null);
      }
    } finally {
      setLoading(false);
      setUpdatingPlan(false);
      setThinking(false);
    }
  };

  const closeAiSettings = () => {
    setAiSettingsClosing(true);
    setTimeout(() => {
      setShowAiSettings(false);
      setAiSettingsClosing(false);
    }, 1000);
  };

  const handleSaveAiPrefs = async () => {
    setSavingPrefs(true);
    try {
      await profileApi.update({ ai_preferences: aiPrefs });
      localStorage.setItem('runwise_ai_prefs', JSON.stringify(aiPrefs));
      closeAiSettings();
    } catch (err) {
      console.error('Failed to save AI prefs:', err);
    } finally {
      setSavingPrefs(false);
    }
  };

  return (
    <div className="screen ai-chat-screen">
      <div className="chat-header">
        <h2 className="screen-title">🤖 {t('chat.title')}</h2>
        <button className="chat-settings-btn" onClick={() => setShowAiSettings(true)} title={t('chat.aiSettings')}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="3"/>
            <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
          </svg>
        </button>
      </div>

      <div className="chat-container">
        <div className="messages" ref={messagesContainerRef} onScroll={handleScroll}>
          {messages.map(message => (
            <ChatMessage key={message.id} message={message} onWorkoutClick={onWorkoutClick} />
          ))}
          {loading && !thinking && (
            <div className="message ai-message">
              <div className="message-content">
                <div className="typing-indicator">
                  <span></span>
                  <span></span>
                  <span></span>
                </div>
              </div>
            </div>
          )}
          {thinking && (
            <div className="message ai-message">
              <div className="message-content">
                <div className="thinking-indicator">
                  <span className="thinking-spinner"></span>
                  {t('chat.analyzing')}
                </div>
              </div>
            </div>
          )}
          {updatingPlan && (
            <div className="message system-message">
              <div className="message-content plan-updating">
                <span className="plan-updating-spinner"></span>
                📝 {t('chat.updatingPlan')}
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="chat-input-area">
          {messageLimit && messageLimit.remaining <= 0 && (
            <div className="chat-limit-banner">{t('chat.limitReached')}</div>
          )}
          <div className="chat-input-wrapper">
            <input
              type="text"
              className="chat-input"
              placeholder={messageLimit && messageLimit.remaining <= 0 ? t('chat.limitReached') : t('chat.placeholder')}
              value={inputValue}
              onChange={e => setInputValue(e.target.value)}
              onKeyDown={e => {
                if (e.key === 'Enter' && !loading && !(messageLimit && messageLimit.remaining <= 0)) {
                  handleSendMessage(inputValue);
                }
              }}
              disabled={loading || (messageLimit !== null && messageLimit.remaining <= 0)}
            />
            <button
              className="chat-send-btn"
              onClick={() => handleSendMessage(inputValue)}
              disabled={loading || (messageLimit !== null && messageLimit.remaining <= 0)}
            >
              ➤
            </button>
          </div>
        </div>
      </div>

      {showAiSettings && ReactDOM.createPortal(
        <div className={`modal-overlay${aiSettingsClosing ? ' modal-closing' : ''}`} onClick={closeAiSettings}>
          <div className={`modal-content${aiSettingsClosing ? ' modal-content-closing' : ''}`} onClick={e => e.stopPropagation()}>
            <h3 className="modal-title">{t('chat.aiSettings')}</h3>

            <div className="ai-settings-section">
              <div className="ai-settings-title">{t('chat.coachGender')}</div>
              <div className="ai-option-group">
                <button
                  className={`ai-option-btn${aiPrefs.coach_gender === 'male' ? ' active' : ''}`}
                  onClick={() => setAiPrefs(p => ({ ...p, coach_gender: 'male' }))}
                >
                  ♂ {t('chat.coachGenderMale')}
                </button>
                <button
                  className={`ai-option-btn${aiPrefs.coach_gender === 'female' ? ' active' : ''}`}
                  onClick={() => setAiPrefs(p => ({ ...p, coach_gender: 'female' }))}
                >
                  ♀ {t('chat.coachGenderFemale')}
                </button>
              </div>
            </div>

            <div className="ai-settings-section">
              <div className="ai-settings-title">{t('chat.personality')}</div>
              <div className="personality-grid">
                {(['bro', 'strict', 'calm', 'motivator'] as const).map(p => (
                  <button
                    key={p}
                    className={`ai-option-btn${aiPrefs.personality === p ? ' active' : ''}`}
                    onClick={() => setAiPrefs(prev => ({ ...prev, personality: p }))}
                  >
                    {p === 'bro' && '😎'} {p === 'strict' && '🎯'} {p === 'calm' && '🧘'} {p === 'motivator' && '🔥'} {t(`chat.personality${p.charAt(0).toUpperCase() + p.slice(1)}`)}
                  </button>
                ))}
              </div>
            </div>

            <div className="ai-settings-section">
              <div className="ai-settings-title">{t('chat.responseLength')}</div>
              <div className="ai-option-group ai-option-group-3">
                {(['short', 'medium', 'long'] as const).map(l => (
                  <button
                    key={l}
                    className={`ai-option-btn${aiPrefs.response_length === l ? ' active' : ''}`}
                    onClick={() => setAiPrefs(p => ({ ...p, response_length: l }))}
                  >
                    {t(`chat.responseLength${l.charAt(0).toUpperCase() + l.slice(1)}`)}
                  </button>
                ))}
              </div>
            </div>

            <div className="ai-settings-section">
              <div className="ai-settings-title">{t('chat.emojiLevel')}</div>
              <div className="ai-option-group">
                <button
                  className={`ai-option-btn${aiPrefs.emoji_level === 'few' ? ' active' : ''}`}
                  onClick={() => setAiPrefs(p => ({ ...p, emoji_level: 'few' }))}
                >
                  {t('chat.emojiFew')}
                </button>
                <button
                  className={`ai-option-btn${aiPrefs.emoji_level === 'many' ? ' active' : ''}`}
                  onClick={() => setAiPrefs(p => ({ ...p, emoji_level: 'many' }))}
                >
                  {t('chat.emojiMany')}
                </button>
              </div>
            </div>

            {messageLimit && (
              <div className="ai-settings-section ai-limit-section">
                <div className="ai-settings-title">{t('chat.dailyLimit')}</div>
                <div className="ai-limit-bar-wrapper">
                  <div className="ai-limit-bar">
                    <div
                      className={`ai-limit-bar-fill${messageLimit.remaining <= 3 ? ' low' : ''}`}
                      style={{ width: `${(messageLimit.remaining / messageLimit.limit) * 100}%` }}
                    />
                  </div>
                  <span className={`ai-limit-text${messageLimit.remaining <= 3 ? ' low' : ''}`}>
                    {t('chat.messagesLeft', { count: messageLimit.remaining, limit: messageLimit.limit })}
                  </span>
                </div>
              </div>
            )}

            <div className="ai-settings-section ai-limit-section">
              <button className="btn btn-danger-outline btn-full" onClick={handleClearHistory}>
                🗑 {t('chat.clearHistory')}
              </button>
            </div>

            <button
              className="btn btn-accent btn-full"
              onClick={handleSaveAiPrefs}
              disabled={savingPrefs}
              style={{ marginTop: '8px' }}
            >
              {savingPrefs ? t('common.saving') : t('common.save')}
            </button>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default AIChat;

