/* ============ AI CHAT SCREEN ============ */
.ai-chat-screen {
  display: flex;
  flex-direction: column;
  height: calc(100vh - 68px);
  overflow: hidden;
  padding: var(--spacing-sm) var(--spacing-lg) 0;
  width: 100%;
  max-width: 420px;
  align-self: center;
}

.chat-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 0;
  margin-bottom: 2px;
  flex-shrink: 0;
}

.chat-header .screen-title {
  margin: 0;
  font-size: 18px;
}

.chat-limit-banner {
  text-align: center;
  font-size: 13px;
  color: #f59e0b;
  padding: 6px 12px;
  background: rgba(245, 158, 11, 0.1);
  border-radius: 8px;
  margin-bottom: 8px;
}


.chat-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  gap: var(--spacing-sm);
}

