3	// Helper: format date as YYYY-MM-DD in local timezone (avoids UTC shift from toISOString)
4	function toLocalDateStr(date) {
5	  const y = date.getFullYear();
6	  const m = String(date.getMonth() + 1).padStart(2, '0');
7	  const d = String(date.getDate()).padStart(2, '0');
8	  return `${y}-${m}-${d}`;
9	}
10	
11	// Helper: format pace from sec/km to mm:ss
12	function formatPace(secPerKm) {
13	  if (!secPerKm) return '—';
14	  const min = Math.floor(secPerKm / 60);
15	  const sec = Math.round(secPerKm % 60);
16	  return `${min}:${sec.toString().padStart(2, '0')}`;
17	}
18	
19	// Helpers: use manual (user-corrected) values if available
20	function effectiveDistance(w) {
21	  return w.manual_distance || w.distance || 0;
22	}
23	function effectiveMovingTime(w) {
24	  return w.manual_moving_time || w.moving_time || 0;
25	}
26	function effectivePace(w) {
27	  const dist = effectiveDistance(w);
28	  const time = effectiveMovingTime(w);
29	  if (w.manual_distance || w.manual_moving_time) {
30	    // Recalculate pace from corrected data
31	    return dist > 0 ? time / (dist / 1000) : null;
32	  }
33	  return w.average_pace;
34	}
35	
36	// Helper: check if user has active premium
37	async function checkPremium(userId) {
38	  const { data: user } = await supabase
39	    .from('users')
40	    .select('premium_until, is_lifetime_premium')
41	    .eq('id', userId)
42	    .single();
43	
44	  if (!user) return false;
45	  if (user.is_lifetime_premium) return true;
46	  if (user.premium_until && new Date(user.premium_until) > new Date()) return true;
47	  return false;
48	}
49	
50	// Helper: count user messages sent today (from daily_usage table, not affected by chat clearing)
51	async function getDailyMessageCount(userId) {
52	  const today = new Date().toISOString().slice(0, 10); // 'YYYY-MM-DD'
53	
54	  const { data, error } = await supabase
55	    .from('daily_usage')
56	    .select('message_count')
57	    .eq('user_id', userId)
58	    .eq('date', today)
59	    .maybeSingle();
60	
61	  if (error) throw error;
62	  return data?.message_count || 0;
63	}
64	
65	// Helper: increment daily message counter (upsert into daily_usage)
66	async function incrementDailyMessageCount(userId) {
67	  const today = new Date().toISOString().slice(0, 10);
68	
69	  const current = await getDailyMessageCount(userId);
70	  const { error } = await supabase
71	    .from('daily_usage')
72	    .upsert(
73	      { user_id: userId, date: today, message_count: current + 1 },
74	      { onConflict: 'user_id,date' }
75	    );
76	
77	  if (error) throw error;
78	}
79	
80	// Helper: get last N months of workouts for AI context
81	async function getWorkoutsContext(userId, months = 3) {
82	  const since = new Date();
83	  since.setMonth(since.getMonth() - months);
84	
85	  const { data } = await supabase
86	    .from('workouts')
87	    .select('name, distance, moving_time, average_pace, average_heartrate, date, type, manual_distance, manual_moving_time')
88	    .eq('user_id', userId)
89	    .gte('date', since.toISOString())
90	    .order('date', { ascending: false });
91	
92	  return (data || []).map(w => ({
93	    date: w.date?.split('T')[0],
94	    name: w.name,
95	    distance_km: (effectiveDistance(w) / 1000).toFixed(2),
96	    pace: formatPace(effectivePace(w)),
97	    heartrate: w.average_heartrate || '—',
98	    type: w.type
99	  }));
100	}
101	
102	// Helper: get compact monthly summary for AI context (replaces raw 3-month dump)
103	async function getMonthlySummaryContext(userId) {
104	  const since = new Date();
105	  since.setDate(since.getDate() - 30);
106	
107	  const { data } = await supabase
108	    .from('workouts')
109	    .select('id, name, distance, moving_time, average_pace, average_heartrate, date, type, total_elevation_gain, manual_distance, manual_moving_time')
110	    .eq('user_id', userId)
111	    .gte('date', since.toISOString())
112	    .order('date', { ascending: false });
113	
114	  const workouts = data || [];
115	  if (workouts.length === 0) {
116	    return {
117	      period: '30 days',
118	      workouts_count: 0,
119	      total_km: 0,
120	      total_time_min: 0,
121	      avg_pace: null,
122	      avg_heartrate: null,
123	      total_elevation: 0
124	    };
125	  }
126	
127	  const totalDist = workouts.reduce((s, w) => s + effectiveDistance(w), 0);
128	  const totalTime = workouts.reduce((s, w) => s + effectiveMovingTime(w), 0);
129	  const totalElev = workouts.reduce((s, w) => s + (w.total_elevation_gain || 0), 0);
130	  const paces = workouts.map(w => effectivePace(w)).filter(Boolean);
131	  const hrs = workouts.filter(w => w.average_heartrate).map(w => w.average_heartrate);
132	
133	  // Type breakdown: count per type
134	  const types = {};
135	  workouts.forEach(w => {
136	    types[w.type || 'other'] = (types[w.type || 'other'] || 0) + 1;
137	  });
138	
139	  return {
140	    period: '30 days',
141	    workouts_count: workouts.length,
142	    total_km: +(totalDist / 1000).toFixed(2),
143	    total_time_min: Math.round(totalTime / 60),
144	    avg_pace: paces.length ? formatPace(paces.reduce((s, p) => s + p, 0) / paces.length) : null,
145	    avg_heartrate: hrs.length ? Math.round(hrs.reduce((s, h) => s + h, 0) / hrs.length) : null,
146	    total_elevation: Math.round(totalElev),
147	    type_breakdown: types
148	  };
149	}
