151	// Helper: get user goals
152	async function getUserGoals(userId) {
153	  const { data } = await supabase
154	    .from('goals')
155	    .select('type, target_value, current_value, created_at, deadline')
156	    .eq('user_id', userId);
157	
158	  return data || [];
159	}
