207	
208	  if (!lastWorkout || lastWorkout.length === 0) {
209	    return { weeks: [0, 0, 0, 0], avg: 0 };
210	  }
211	
212	  // Find Monday of the week AFTER last workout (anchor point)
213	  const lastDate = new Date(lastWorkout[0].date);
214	  const dow = lastDate.getDay();
215	  const daysUntilNextMonday = dow === 0 ? 1 : 8 - dow;
216	  const anchor = new Date(lastDate);
217	  anchor.setHours(0, 0, 0, 0);
218	  anchor.setDate(anchor.getDate() + daysUntilNextMonday);
219	
220	  // Load 4 weeks of workouts before anchor
221	  const since = new Date(anchor);
222	  since.setDate(since.getDate() - 28);
223	
224	  const { data } = await supabase
225	    .from('workouts')
226	    .select('date, distance, manual_distance')
227	    .eq('user_id', userId)
228	    .gte('date', since.toISOString())
229	    .lt('date', anchor.toISOString())
230	    .order('date', { ascending: false });
231	
232	  const workouts = data || [];
233	
234	  const weeks = [];
235	  for (let w = 0; w < 4; w++) {
236	    const weekEnd = new Date(anchor);
237	    weekEnd.setDate(weekEnd.getDate() - w * 7);
238	    const weekStart = new Date(weekEnd);
239	    weekStart.setDate(weekStart.getDate() - 7);
240	
241	    const totalKm = workouts
242	      .filter(wr => { const d = new Date(wr.date); return d >= weekStart && d < weekEnd; })
243	      .reduce((s, wr) => s + effectiveDistance(wr) / 1000, 0);
244	    weeks.push(Math.round(totalKm * 10) / 10);
245	  }
246	
247	  const avg = weeks.length > 0
248	    ? Math.round(weeks.reduce((a, b) => a + b, 0) / weeks.length * 10) / 10
249	    : 0;
250	  return { weeks, avg };
