299	function getRecentPaceStats(workouts) {
300	  if (!workouts || !workouts.length) return { avgPace: null, avgEasyPace: null, bestPace: null, count: 0 };
301	
302	  const runWorkouts = workouts.filter(w => {
303	    const dist = effectiveDistance(w);
304	    return dist >= 2000; // минимум 2 км
305	  });
306	
307	  const paces = runWorkouts
308	    .map(w => effectivePace(w))
309	    .filter(p => p && p > 0);
310	
311	  if (!paces.length) return { avgPace: null, avgEasyPace: null, bestPace: null, count: 0 };
312	
313	  const avgPace = Math.round(paces.reduce((a, b) => a + b, 0) / paces.length);
314	  const bestPace = Math.min(...paces);
315	
316	  // Easy-тренировки: темп медленнее среднего (верхние 60% по темпу = более медленные)
317	  const sorted = [...paces].sort((a, b) => a - b);
318	  const easyThreshold = Math.ceil(sorted.length * 0.4);
319	  const easyPaces = sorted.slice(easyThreshold); // медленная часть
320	  const avgEasyPace = easyPaces.length
321	    ? Math.round(easyPaces.reduce((a, b) => a + b, 0) / easyPaces.length)
322	    : avgPace;
323	
324	  return { avgPace, avgEasyPace, bestPace, count: paces.length };
