340	// Helper: compute plan-vs-fact actuals for past weeks of a macro plan
341	async function computeMacroPlanWithActuals(userId, macroPlan) {
342	  if (!macroPlan || !macroPlan.weeks || macroPlan.weeks.length === 0) {
343	    return { ...macroPlan, current_week: 1 };
344	  }
345	
346	  const weeks = typeof macroPlan.weeks === 'string'
347	    ? JSON.parse(macroPlan.weeks)
348	    : macroPlan.weeks;
349	
350	  const today = new Date();
351	  today.setHours(0, 0, 0, 0);
352	
353	  const firstStart = new Date(weeks[0].start_date);
354	  const diffDays = Math.floor((today - firstStart) / (1000 * 60 * 60 * 24));
355	  const currentWeek = Math.max(1, Math.min(Math.floor(diffDays / 7) + 1, weeks.length));
356	
357	  // Find range of past weeks to query workouts
358	  const pastWeeks = weeks.filter(w => {
359	    const weekEnd = new Date(w.start_date);
360	    weekEnd.setDate(weekEnd.getDate() + 7);
361	    return weekEnd <= today;
362	  });
363	
364	  if (pastWeeks.length === 0) {
365	    return { ...macroPlan, weeks, current_week: currentWeek };
366	  }
367	
368	  // Single query for all past weeks' workouts
369	  const planStart = pastWeeks[0].start_date;
370	  const lastPastWeekEnd = new Date(pastWeeks[pastWeeks.length - 1].start_date);
371	  lastPastWeekEnd.setDate(lastPastWeekEnd.getDate() + 7);
372	
373	  const { data: workouts } = await supabase
374	    .from('workouts')
375	    .select('distance, moving_time, date, manual_distance, manual_moving_time')
376	    .eq('user_id', userId)
377	    .gte('date', planStart)
378	    .lt('date', lastPastWeekEnd.toISOString())
379	    .order('date', { ascending: true });
380	
381	  const allWorkouts = workouts || [];
382	
383	  // Bucket workouts by week
384	  const enrichedWeeks = weeks.map(w => {
385	    const weekStart = new Date(w.start_date);
386	    const weekEnd = new Date(w.start_date);
387	    weekEnd.setDate(weekEnd.getDate() + 7);
388	
389	    if (weekEnd > today) {
390	      // Future or current week — no actuals
391	      return { ...w };
392	    }
393	
394	    const weekWorkouts = allWorkouts.filter(wr => {
395	      const d = new Date(wr.date);
396	      return d >= weekStart && d < weekEnd;
397	    });
398	
399	    const actualKm = weekWorkouts.reduce((s, wr) => s + effectiveDistance(wr) / 1000, 0);
400	    const actualSessions = weekWorkouts.length;
401	    const compliance = w.target_volume_km > 0
402	      ? Math.min(Math.round((actualKm / w.target_volume_km) * 100), 200)
403	      : 100;
404	
405	    return {
406	      ...w,
407	      actual_volume_km: Math.round(actualKm * 10) / 10,
408	      actual_sessions: actualSessions,
409	      compliance_pct: compliance
410	    };
411	  });
412	
413	  return {
414	    ...macroPlan,
415	    weeks: enrichedWeeks,
416	    current_week: currentWeek
417	  };
418	}
