420	/**
421	 * Анализ стабильности тренировок за последние N недель
422	 * @param {string} userId
423	 * @param {number} weeksCount - количество недель для анализа (по умолчанию 12)
424	 * @returns {object} { isStable, avgVolume, volumeStdDev, gapWeeks, consistency }
425	 */
426	async function analyzeTrainingStability(userId, weeksCount = 12) {
427	  const since = new Date();
428	  since.setDate(since.getDate() - weeksCount * 7);
429	
430	  const { data: workouts } = await supabase
431	    .from('workouts')
432	    .select('date, distance, manual_distance')
433	    .eq('user_id', userId)
434	    .gte('date', since.toISOString())
435	    .order('date', { ascending: true });
436	
437	  if (!workouts || workouts.length === 0) {
438	    return {
439	      isStable: false,
440	      avgVolume: 0,
441	      volumeStdDev: 0,
442	      gapWeeks: weeksCount,
443	      consistency: 0,
444	      weeklyVolumes: []
445	    };
446	  }
447	
448	  // Разбить на недели
449	  const weeklyVolumes = [];
450	  const today = new Date();
451	  today.setHours(0, 0, 0, 0);
452	
453	  for (let w = 0; w < weeksCount; w++) {
454	    const weekEnd = new Date(today);
455	    weekEnd.setDate(weekEnd.getDate() - w * 7);
456	    const weekStart = new Date(weekEnd);
457	    weekStart.setDate(weekStart.getDate() - 7);
458	
459	    const weekWorkouts = workouts.filter(wr => {
460	      const d = new Date(wr.date);
461	      return d >= weekStart && d < weekEnd;
462	    });
463	
464	    const totalKm = weekWorkouts.reduce((s, wr) => s + effectiveDistance(wr) / 1000, 0);
465	    weeklyVolumes.push(Math.round(totalKm * 10) / 10);
466	  }
467	
468	  weeklyVolumes.reverse(); // от старой к новой
469	
470	  // Средний объём
471	  const avgVolume = weeklyVolumes.reduce((a, b) => a + b, 0) / weeklyVolumes.length;
472	
473	  // Стандартное отклонение
474	  const variance = weeklyVolumes.reduce((sum, v) => sum + Math.pow(v - avgVolume, 2), 0) / weeklyVolumes.length;
475	  const volumeStdDev = Math.sqrt(variance);
476	
477	  // Количество недель с нулевым объёмом (пропуски)
478	  const gapWeeks = weeklyVolumes.filter(v => v === 0).length;
479	
480	  // Коэффициент вариации (CV) — мера стабильности
481	  // CV < 0.3 = стабильно, 0.3-0.5 = умеренно, >0.5 = нестабильно
482	  const cv = avgVolume > 0 ? volumeStdDev / avgVolume : 1;
483	
484	  // Consistency score (0-100): учитывает CV и пропуски
485	  const gapPenalty = (gapWeeks / weeksCount) * 50; // до 50% штрафа за пропуски
486	  const cvScore = Math.max(0, 100 - cv * 100); // чем меньше CV, тем выше балл
487	  const consistency = Math.max(0, Math.round(cvScore - gapPenalty));
488	
489	  // Стабильность: consistency > 60 и пропусков < 25%
490	  const isStable = consistency > 60 && gapWeeks < weeksCount * 0.25;
491	
492	  return {
493	    isStable,
494	    avgVolume: Math.round(avgVolume * 10) / 10,
495	    volumeStdDev: Math.round(volumeStdDev * 10) / 10,
496	    gapWeeks,
497	    consistency,
498	    weeklyVolumes,
499	    coefficientOfVariation: Math.round(cv * 100) / 100
500	  };
501	}
