503	/**
504	 * Оценка реалистичности цели марафона
505	 * @param {number} currentVDOT - текущий VDOT пользователя
506	 * @param {number} targetTimeSeconds - целевое время марафона в секундах
507	 * @param {number} weeksAvailable - количество недель до забега
508	 * @returns {object} { isRealistic, currentPrediction, requiredImprovement, recommendedTime }
509	 */
510	function assessMarathonGoalRealism(currentVDOT, targetTimeSeconds, weeksAvailable) {
511	  if (!currentVDOT || !targetTimeSeconds || !weeksAvailable) {
512	    return { isRealistic: null, currentPrediction: null, requiredImprovement: null, recommendedTime: null };
513	  }
514	
515	  // Формула Дэниелса для предсказания времени марафона по VDOT
516	  // Упрощённая версия: marathon pace (sec/km) ≈ функция от VDOT
517	  // Используем обратную формулу из vdot.js
518	  const { calculatePaceZones } = require('./vdot');
519	  const zones = calculatePaceZones(currentVDOT);
520	  
521	  if (!zones || !zones.marathon) {
522	    return { isRealistic: null, currentPrediction: null, requiredImprovement: null, recommendedTime: null };
523	  }
524	
525	  // Текущее предсказание времени марафона (42.195 км)
526	  const currentMarathonPace = zones.marathon; // сек/км
527	  const currentPrediction = Math.round(currentMarathonPace * 42.195);
528	
529	  // Целевой темп
530	  const targetPace = targetTimeSeconds / 42.195;
531	
532	  // Требуемое улучшение темпа (сек/км)
533	  const paceImprovement = currentMarathonPace - targetPace;
534	
535	  // Требуемое улучшение VDOT
536	  // Примерно: 1 единица VDOT ≈ 3-5 сек/км улучшения марафонского темпа
537	  const requiredVDOTImprovement = paceImprovement / 4; // грубая оценка
538	
539	  // Реалистичное улучшение VDOT за доступное время
540	  // Средний прогресс: 1-3% в месяц, возьмём 2% как среднее
541	  const monthsAvailable = weeksAvailable / 4.33;
542	  const realisticVDOTGain = currentVDOT * 0.02 * monthsAvailable;
543	
544	  // Рекомендуемый VDOT через N месяцев
545	  const recommendedVDOT = currentVDOT + realisticVDOTGain;
546	  const recommendedZones = calculatePaceZones(recommendedVDOT);
547	  const recommendedTime = recommendedZones ? Math.round(recommendedZones.marathon * 42.195) : null;
548	
549	  // Требуемый месячный прогресс
550	  const requiredMonthlyImprovement = (requiredVDOTImprovement / currentVDOT) / monthsAvailable;
551	
552	  // Реалистично если требуется <5% улучшения в месяц
553	  const isRealistic = requiredMonthlyImprovement < 0.05;
554	
555	  return {
556	    isRealistic,
557	    currentPrediction,
558	    targetTime: targetTimeSeconds,
559	    requiredImprovement: Math.round(requiredMonthlyImprovement * 100 * 10) / 10, // % в месяц
560	    recommendedTime,
561	    currentVDOT: Math.round(currentVDOT * 10) / 10,
562	    recommendedVDOT: Math.round(recommendedVDOT * 10) / 10,
563	    weeksAvailable,
564	    paceImprovementNeeded: Math.round(paceImprovement)
565	  };
566	}
