569	function analyzeRecentCompliance(macroPlan) {
570	  if (!macroPlan?.weeks) return null;
571	
572	  const completedWeeks = macroPlan.weeks.filter(w => w.compliance_pct !== undefined);
573	  if (completedWeeks.length === 0) return null;
574	
575	  const recent = completedWeeks.slice(-4);
576	  const avgCompliance = Math.round(recent.reduce((s, w) => s + w.compliance_pct, 0) / recent.length);
577	
578	  // Trend: is compliance improving or declining
579	  const trend = recent.length >= 2
580	    ? recent[recent.length - 1].compliance_pct - recent[0].compliance_pct
581	    : 0;
582	
583	  // Count consecutive low/high compliance weeks (from the end)
584	  let consecutiveLow = 0;
585	  for (let i = completedWeeks.length - 1; i >= 0; i--) {
586	    if (completedWeeks[i].compliance_pct < 80) consecutiveLow++;
587	    else break;
588	  }
589	
590	  let consecutiveHigh = 0;
591	  for (let i = completedWeeks.length - 1; i >= 0; i--) {
592	    if (completedWeeks[i].compliance_pct > 115) consecutiveHigh++;
593	    else break;
594	  }
595	
596	  return {
597	    avgCompliance,
598	    trend,
599	    consecutiveLow,
600	    consecutiveHigh,
601	    needsAdjustment: consecutiveLow >= 2 || consecutiveHigh >= 2,
602	    weeksCompleted: completedWeeks.length,
603	    totalWeeks: macroPlan.weeks.length
604	  };
605	}
