    en: { '1km': '1 km', '3km': '3 km', '5km': '5 km', '10km': '10 km', '21km': 'Half marathon (21.1 km)', '42km': 'Marathon (42.2 km)' }
  };
  const labels = DISTANCE_LABELS_I18N[lang] || DISTANCE_LABELS_I18N.ru;
