      if (eDist && eDist >= 1000 && eDist < targetDistM * 0.95 && e.moving_time > 0) {
        const rTime = e.moving_time * Math.pow(targetDistM / eDist, riegelExp);
        allRiegelResults.push({
          time: rTime,
          timeFormatted: fmtTime(Math.round(rTime)),
