            };
          } else {
            finalTime = riegelEstimate;
            source = 'riegel';
            breakdown.chosen = {
              source: 'Формула Ригеля',
              reason: `Расчёт по тренировке ${riegelBasis.distKm} км от ${riegelBasis.dateFormatted} (${fmtTime(riegelEstimate)}) быстрее сплита (${fmtTime(Math.round(bestEffort.time))})`,
            };
