        } else if (bestEffort) {
          finalTime = Math.round(bestEffort.time);
          source = 'best_effort';
          breakdown.chosen = {
            source: 'Strava-сплит',
            reason: `Нет подходящих тренировок для Ригеля, используется ${targetBEName}-сплит`,
