// API URL: uses env variable in production, localhost for dev
const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001';

function getToken(): string | null {
  return localStorage.getItem('runwise_token');
}

function getLang(): string {
  return localStorage.getItem('runwise_language') || 'ru';
}

async function request(endpoint: string, options: RequestInit = {}): Promise<any> {
  const token = getToken();
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    ...(options.headers as Record<string, string> || {})
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  const response = await fetch(`${API_URL}${endpoint}`, {
    ...options,
    headers
  });

  if (response.status === 401) {
    localStorage.removeItem('runwise_token');
    window.location.href = '/';
    throw new Error('Unauthorized');
  }

  if (!response.ok) {
    const error = await response.json().catch(() => ({ error: 'Request failed' }));
    throw new Error(error.error || 'Request failed');
  }

  return response.json();
}

// ============ TYPES ============

export interface AiPreferences {
  coach_gender?: 'male' | 'female';
  response_length?: 'short' | 'medium' | 'long';
  personality?: 'bro' | 'strict' | 'calm' | 'motivator';
  humor?: boolean;
  emoji_level?: 'few' | 'many';
}

// ============ AUTH ============

export const auth = {
  getStravaUrl: () => request('/api/auth/strava'),
  callback: (code: string) => request('/api/auth/callback', {
    method: 'POST',
    body: JSON.stringify({ code })
  }),
  me: () => request('/api/auth/me')
};

// ============ STRAVA ============

export const strava = {
  sync: () => request('/api/strava/sync', { method: 'POST' }),
  syncAll: () => request('/api/strava/sync-all', { method: 'POST' }),
  syncSplits: (workoutId: string) => request(`/api/strava/sync-splits/${workoutId}`, { method: 'POST' }),
  syncSplits500: (workoutId: string) => request(`/api/strava/sync-splits-500/${workoutId}`, { method: 'POST' }),
  syncStatus: () => request('/api/strava/sync-status'),
  rateLimit: () => request('/api/strava/rate-limit'),
  adminRateLimit: (secret: string) => request('/api/strava/rate-limit/global', {
    headers: { 'X-Admin-Secret': secret } as any
  }),
  adminWebhookLog: (secret: string) => request('/api/strava/webhook-log', {
    headers: { 'X-Admin-Secret': secret } as any
  })
};

// ============ WORKOUTS ============

export const workouts = {
  list: (params?: { month?: number; year?: number; limit?: number }) => {
    const searchParams = new URLSearchParams();
    if (params?.month) searchParams.set('month', params.month.toString());
    if (params?.year) searchParams.set('year', params.year.toString());
    if (params?.limit) searchParams.set('limit', params.limit.toString());
    const qs = searchParams.toString();
    return request(`/api/workouts${qs ? `?${qs}` : ''}`);
  },
  get: (id: string) => request(`/api/workouts/${id}`),
  update: (id: string, data: { action: 'verify' } | { action: 'edit'; manual_distance: number; manual_moving_time: number }) =>
    request(`/api/workouts/${id}`, { method: 'PATCH', body: JSON.stringify(data) }),
  reanalyze: () => request('/api/workouts/reanalyze', { method: 'POST' }),
  stats: (period: 'week' | 'month' | 'all') => request(`/api/workouts/stats?period=${period}`),
  weekly: () => {
    const tz = -(new Date().getTimezoneOffset() / 60);
    return request(`/api/workouts/weekly?tz=${tz}`);
  },
  getGoals: () => request('/api/workouts/goals/list'),
  createGoal: (type: string, targetValue: number, deadline?: string) => request('/api/workouts/goals', {
    method: 'POST',
    body: JSON.stringify({ type, target_value: targetValue, deadline: deadline || null })
  }),
  updateGoal: (id: string, targetValue: number, deadline?: string) => request(`/api/workouts/goals/${id}`, {
    method: 'PUT',
    body: JSON.stringify({ target_value: targetValue, deadline: deadline || null })
  }),
  deleteGoal: (id: string) => request(`/api/workouts/goals/${id}`, { method: 'DELETE' }),
  goalPredictions: () => request('/api/workouts/goals/predictions'),
  comparison: () => request('/api/workouts/comparison')
};

// ============ PROFILE ============

export const profile = {
  get: () => request('/api/profile'),
  update: (data: { age?: number | null; height_cm?: number | null; weight_kg?: number | null; gender?: string | null; ai_preferences?: AiPreferences }) =>
    request('/api/profile', { method: 'PUT', body: JSON.stringify(data) }),
  getRecords: () => request('/api/profile/records'),
  updateRecord: (data: { distance_type: string; time_seconds: number; record_date?: string }) =>
    request('/api/profile/records', { method: 'PUT', body: JSON.stringify(data) }),
  deleteRecord: (type: string) =>
    request(`/api/profile/records/${type}`, { method: 'DELETE' }),
};

// ============ PROMO ============

export const promo = {
  activate: (code: string) => request('/api/promo/activate', {
    method: 'POST',
    body: JSON.stringify({ code })
  }),
  status: () => request('/api/promo/status'),
  adminList: (secret: string) => request('/api/promo/admin/codes', {
    headers: { 'X-Admin-Secret': secret } as any
  }),
  adminCreate: (secret: string, data: { code: string; duration_days?: number | null; max_uses?: number }) =>
    request('/api/promo/admin/codes', {
      method: 'POST',
      headers: { 'X-Admin-Secret': secret } as any,
      body: JSON.stringify(data)
    }),
  adminDelete: (secret: string, id: string) =>
    request(`/api/promo/admin/codes/${id}`, {
      method: 'DELETE',
      headers: { 'X-Admin-Secret': secret } as any
    }),
  adminActivations: (secret: string) => request('/api/promo/admin/activations', {
    headers: { 'X-Admin-Secret': secret } as any
  })
};

// ============ AI ============

export const ai = {
  chat: (message: string) => request('/api/ai/chat', {
    method: 'POST',
    body: JSON.stringify({ message, lang: getLang() })
  }),
  chatStream: async (
    message: string,
    onChunk: (text: string) => void,
    onDone: (meta: { planUpdated: boolean; macroPlanUpdated?: boolean; macroPlanAction?: string }) => void,
    onThinking?: () => void
  ): Promise<void> => {
    const token = getToken();
    const response = await fetch(`${API_URL}/api/ai/chat/stream`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { 'Authorization': `Bearer ${token}` } : {})
      },
      body: JSON.stringify({ message, lang: getLang() })
    });

    if (response.status === 401) {
      localStorage.removeItem('runwise_token');
      window.location.href = '/';
      throw new Error('Unauthorized');
    }

    if (!response.ok) {
      if (response.status === 429) {
        throw new Error('Daily message limit reached');
      }
      throw new Error('Stream request failed');
    }

    const reader = response.body?.getReader();
    if (!reader) throw new Error('No response body');

    const decoder = new TextDecoder();
    let buffer = '';
    let done = false;

    while (!done) {
      const { value, done: readerDone } = await reader.read();
      done = readerDone;

      if (value) {
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || !trimmed.startsWith('data: ')) continue;

          const payload = trimmed.slice(6);
          if (payload === '[DONE]') continue;

          try {
            const json = JSON.parse(payload);
            if (json.meta) {
              onDone(json.meta);
              continue;
            }
            if (json.thinking && onThinking) {
              onThinking();
              continue;
            }
            const content = json.choices?.[0]?.delta?.content;
            if (content) {
              onChunk(content);
            }
          } catch {
            // Not valid JSON, skip
          }
        }
      }
    }
  },
  chatLimit: () => request('/api/ai/chat/limit'),
  chatHistory: () => request('/api/ai/chat/history'),
  clearChatHistory: () => request('/api/ai/chat/history', { method: 'DELETE' }),
  analyzeWorkout: (workoutId: string) => request('/api/ai/analyze-workout', {
    method: 'POST',
    body: JSON.stringify({ workoutId, lang: getLang() })
  }),
  generatePlan: () => request('/api/ai/generate-plan', {
    method: 'POST',
    body: JSON.stringify({ lang: getLang() })
  }),
  getPlan: () => request('/api/ai/plan'),
  getMacroPlan: () => request('/api/ai/macro-plan'),
  deleteMacroPlan: () => request('/api/ai/macro-plan', { method: 'DELETE' }),
  weeklyAnalysis: () => request('/api/ai/weekly-analysis', {
    method: 'POST',
    body: JSON.stringify({ lang: getLang() })
  }),
  getPaceZones: () => request('/api/ai/pace-zones')
};

