    easy: ZoneRange;
    marathon: ZoneRange;
    threshold: ZoneRange;
    interval: ZoneRange;
    repetition: ZoneRange;
  } | null;
  details: {
    source: 'records' | 'workouts' | 'decay' | null;
    weeklyKm: number;
    workoutsCount: number;
    avgPace: string | null;
    bestPace: string | null;
    recordsBreakdown: Array<{
      distance: string;
      time_seconds: number;
      date: string | null;
      vdot: number;
    }>;
    sourceWorkout: SourceWorkout | null;
    otherGoodWorkouts: SourceWorkout[];
  };
}

interface PaceZonesProps {
  onWorkoutClick?: (id: string) => void;
  openModal?: boolean;
  onModalOpened?: () => void;
  maxHR?: number | null;
}

const PaceZonesSection: React.FC<PaceZonesProps> = ({ onWorkoutClick, openModal, onModalOpened, maxHR }) => {
  const { t } = useTranslation();
  const [data, setData] = useState<PaceZonesData | null>(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [modalClosing, setModalClosing] = useState(false);

  useEffect(() => {
    ai.getPaceZones()
      .then((res: PaceZonesData) => setData(res))
      .catch(() => setData(null))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (openModal && !loading && data?.vdot) {
      setModalClosing(false);
      setShowModal(true);
      onModalOpened?.();
    }
  }, [openModal, loading, data]);

  const closeModal = () => {
    setModalClosing(true);
    setTimeout(() => { setShowModal(false); setModalClosing(false); }, 300);
  };

  if (loading || !data?.vdot || !data?.zones) return null;

  const levelLabels: Record<string, string> = {
    beginner: t('paceZones.beginner'),
    intermediate: t('paceZones.intermediate'),
    advanced: t('paceZones.advanced')
